func NewRelationsValueMust(attributeTypes map[string]attr.Type, attributes map[string]attr.Value) RelationsValue {
	object, diags := NewRelationsValue(attributeTypes, attributes)

	if diags.HasError() {
		// This could potentially be added to the diag package.
		diagsStrings := make([]string, 0, len(diags))

		for _, diagnostic := range diags {
			diagsStrings = append(diagsStrings, fmt.Sprintf(
				"%s | %s | %s",
				diagnostic.Severity(),
				diagnostic.Summary(),
				diagnostic.Detail()))
		}

		panic("NewRelationsValueMust received error(s): " + strings.Join(diagsStrings, "\n"))
	}

	return object
}

func (t RelationsType) ValueFromTerraform(ctx context.Context, in tftypes.Value) (attr.Value, error) {
	if in.Type() == nil {
		return NewRelationsValueNull(), nil
	}

	if !in.Type().Equal(t.TerraformType(ctx)) {
		return nil, fmt.Errorf("expected %s, got %s", t.TerraformType(ctx), in.Type())
	}

	if !in.IsKnown() {
		return NewRelationsValueUnknown(), nil
	}

	if in.IsNull() {
		return NewRelationsValueNull(), nil
	}

	attributes := map[string]attr.Value{}

	val := map[string]tftypes.Value{}

	err := in.As(&val)

	if err != nil {
		return nil, err
	}

	for k, v := range val {
		a, err := t.AttrTypes[k].ValueFromTerraform(ctx, v)

		if err != nil {
			return nil, err
		}

		attributes[k] = a
	}

	return NewRelationsValueMust(RelationsValue{}.AttributeTypes(ctx), attributes), nil
}

func (t RelationsType) ValueType(ctx context.Context) attr.Value {
	return RelationsValue{}
}

var _ basetypes.ObjectValuable = RelationsValue{}

type RelationsValue struct {
	Hops          basetypes.Int64Value  `tfsdk:"hops"`
	Id            basetypes.StringValue `tfsdk:"id"`
	Name          basetypes.StringValue `tfsdk:"name"`
	Relation      basetypes.StringValue `tfsdk:"relation"`
	ServiceType   basetypes.StringValue `tfsdk:"service_type"`
	RelationsType basetypes.StringValue `tfsdk:"type"`
	state         attr.ValueState
}

func (v RelationsValue) ToTerraformValue(ctx context.Context) (tftypes.Value, error) {
	attrTypes := make(map[string]tftypes.Type, 6)

	var val tftypes.Value
	var err error

	attrTypes["hops"] = basetypes.Int64Type{}.TerraformType(ctx)
	attrTypes["id"] = basetypes.StringType{}.TerraformType(ctx)
	attrTypes["name"] = basetypes.StringType{}.TerraformType(ctx)
	attrTypes["relation"] = basetypes.StringType{}.TerraformType(ctx)
	attrTypes["service_type"] = basetypes.StringType{}.TerraformType(ctx)
	attrTypes["type"] = basetypes.StringType{}.TerraformType(ctx)

	objectType := tftypes.Object{AttributeTypes: attrTypes}

	switch v.state {
	case attr.ValueStateKnown:
		vals := make(map[string]tftypes.Value, 6)

		val, err = v.Hops.ToTerraformValue(ctx)

		if err != nil {
			return tftypes.NewValue(objectType, tftypes.UnknownValue), err
		}

		vals["hops"] = val

		val, err = v.Id.ToTerraformValue(ctx)

		if err != nil {
			return tftypes.NewValue(objectType, tftypes.UnknownValue), err
		}

		vals["id"] = val

		val, err = v.Name.ToTerraformValue(ctx)

		if err != nil {
			return tftypes.NewValue(objectType, tftypes.UnknownValue), err
		}

		vals["name"] = val

		val, err = v.Relation.ToTerraformValue(ctx)

		if err != nil {
			return tftypes.NewValue(objectType, tftypes.UnknownValue), err
		}

		vals["relation"] = val

		val, err = v.ServiceType.ToTerraformValue(ctx)

		if err != nil {
			return tftypes.NewValue(objectType, tftypes.UnknownValue), err
		}

		vals["service_type"] = val

		val, err = v.RelationsType.ToTerraformValue(ctx)

		if err != nil {
			return tftypes.NewValue(objectType, tftypes.UnknownValue), err
		}

		vals["type"] = val

		if err := tftypes.ValidateValue(objectType, vals); err != nil {
			return tftypes.NewValue(objectType, tftypes.UnknownValue), err
		}

		return tftypes.NewValue(objectType, vals), nil
	case attr.ValueStateNull:
		return tftypes.NewValue(objectType, nil), nil
	case attr.ValueStateUnknown:
		return tftypes.NewValue(objectType, tftypes.UnknownValue), nil
	default:
		panic(fmt.Sprintf("unhandled Object state in ToTerraformValue: %s", v.state))
	}
}

func (v RelationsValue) IsNull() bool {
	return v.state == attr.ValueStateNull
}

func (v RelationsValue) IsUnknown() bool {
	return v.state == attr.ValueStateUnknown
}

func (v RelationsValue) String() string {
	return "RelationsValue"
}

func (v RelationsValue) ToObjectValue(ctx context.Context) (basetypes.ObjectValue, diag.Diagnostics) {
	var diags diag.Diagnostics

	attributeTypes := map[string]attr.Type{
		"hops":         basetypes.Int64Type{},
		"id":           basetypes.StringType{},
		"name":         basetypes.StringType{},
		"relation":     basetypes.StringType{},
		"service_type": basetypes.StringType{},
		"type":         basetypes.StringType{},
	}

	if v.IsNull() {
		return types.ObjectNull(attributeTypes), diags
	}

	if v.IsUnknown() {
		return types.ObjectUnknown(attributeTypes), diags
	}

	objVal, diags := types.ObjectValue(
		attributeTypes,
		map[string]attr.Value{
			"hops":         v.Hops,
			"id":           v.Id,
			"name":         v.Name,
			"relation":     v.Relation,
			"service_type": v.ServiceType,
			"type":         v.RelationsType,
		})

	return objVal, diags
}

func (v RelationsValue) Equal(o attr.Value) bool {
	other, ok := o.(RelationsValue)

	if !ok {
		return false
	}

	if v.state != other.state {
		return false
	}

	if v.state != attr.ValueStateKnown {
		return true
	}

	if !v.Hops.Equal(other.Hops) {
		return false
	}

	if !v.Id.Equal(other.Id) {
		return false
	}

	if !v.Name.Equal(other.Name) {
		return false
	}

	if !v.Relation.Equal(other.Relation) {
		return false
	}

	if !v.ServiceType.Equal(other.ServiceType) {
		return false
	}

	if !v.RelationsType.Equal(other.RelationsType) {
		return false
	}

	return true
}

func (v RelationsValue) Type(ctx context.Context) attr.Type {
	return RelationsType{
		basetypes.ObjectType{
			AttrTypes: v.AttributeTypes(ctx),
		},
	}
}

func (v RelationsValue) AttributeTypes(ctx context.Context) map[string]attr.Type {
	return map[string]attr.Type{
		"hops":         basetypes.Int64Type{},
		"id":           basetypes.StringType{},
		"name":         basetypes.StringType{},
		"relation":     basetypes.StringType{},
		"service_type": basetypes.StringType{},
		"type":         basetypes.StringType{},
	}
}
